		//-------------------------------------  JudgmentCourt_OKBtn  ------------------------------------------
		
		    function JudgmentCourt_OKBtn(){}
		    JudgmentCourt_OKBtn.actionBinding = function()
		    {       
		        var venueCode = Services.getValue(JudgmentCourt_VenueCode.dataBinding);
		        var venueName = Services.getValue(JudgmentCourt_VenueName.dataBinding);
		        //var addressId = Services.getValue(selectVenue_Address_Grid.dataBinding);
		    
		        // Need to ensure all mandatory data is entered and all data is valid
		        // If a venue has been selected the address fields are populated automatically.
		        // Just need to ensure that the first address line has detail in and 
		        // therefore no need to validate the other address field   s.
		        var screenValid = true;
		        if((venueCode == null || venueCode == "") || (venueName == null || venueName == ""))
		        {
		            screenValid = false;    
		        }
		    
		        if(screenValid)
		        {
		        //if (confirm("feel like debugging?")) debugger;
		        //something buggy? going on with autocomplete gui: returns a code instead of name
		        
		        //check venue name is a code
		        var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourt_VenueName.dataBinding + "]/Name";     
		        var checkVenueName = Services.getValue(xpathName);
		        if( null != checkVenueName && checkVenueName.length > 0)   
		        {  //value of checkVenueName is actually a code
		            //replace code with venuename
		            venueName = checkVenueName;
		        }
		            
		        // Set the data in the business part of the model       
		        Services.setValue(JudgmentCourtCode.dataBinding, venueCode);        
		        Services.setValue(JudgmentCourtName.dataBinding, venueName);
		        
		        
		        Services.setValue(JudgmentCourtName.dataBinding, venueName);
		        
		        
		        
		        FormController.getInstance().hideFormExtensionPopup("JudgmentCourt");       
		        }      
		        else{
					alert("Please ensure you have selected valid venue details.");
				} 
		        
		    }
			JudgmentCourt_OKBtn.tabIndex = __tabIdx++;

		
		
		//-------------------------------------  JudgmentCourt_CancelBtn  --------------------------------------    
		
		    function JudgmentCourt_CancelBtn(){}
			JudgmentCourt_CancelBtn.tabIndex = __tabIdx++;

		//------------------------------------  JudgmentCourt_VenueCode  ---------------------------------------
		
		    function JudgmentCourt_VenueCode(){}
		    JudgmentCourt_VenueCode.dataBinding = "/ds/EnterVariableData/FastTrack/JudgmentCourt_VenueCode";
		   	JudgmentCourt_VenueCode.tabIndex = __tabIdx++;
		    JudgmentCourt_VenueCode.helpText = "Unique three digit court location code - list available.";
		    JudgmentCourt_VenueCode.maxLength = 3;
		    JudgmentCourt_VenueCode.logicOn = [JudgmentCourt_VenueCode.dataBinding];
		    JudgmentCourt_VenueCode.logic = function()
		    {   
		        var code = Services.getValue(JudgmentCourt_VenueCode.dataBinding);
		        var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourt_VenueCode.dataBinding + "]/Name";
		        var xpathId = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourt_VenueCode.dataBinding + "]/Id";
		        var venueName = Services.getValue(xpathName);
		        var venueId = Services.getValue(xpathId);
		    
		        // Set the data in the business part of the model
		        if(venueName != null && venueName != ""){
		            // set the description field appropriately
		            Services.setValue(JudgmentCourt_VenueName.dataBinding, code);      
		            Services.setValue(JudgmentCourtCourtsLOVGrid.dataBinding, code);     
		        }
		        else{
		            // Clear the fields
		            Services.setValue(JudgmentCourt_VenueName.dataBinding, "");
		            Services.setValue(JudgmentCourt_VenueCode.dataBinding, "");
		            Services.setValue(JudgmentCourtCourtsLOVGrid.dataBinding, "");  
		        }               
		    }
		//  JudgmentCourt_VenueCode.validateOn = [JudgmentCourt_VenueCode.dataBinding, JudgmentCourt_VenueName.dataBinding];
		//  JudgmentCourt_VenueCode.validate = function(){ return null;}
		    
		    
		    
		//-----------------------------------  JudgmentCourt_VenueName  ----------------------------------------
		
		    function JudgmentCourt_VenueName(){}
		    JudgmentCourt_VenueName.dataBinding = "/ds/EnterVariableData/FastTrack/JudgmentCourt_VenueName";
		    JudgmentCourt_VenueName.tabIndex = __tabIdx++;
		    JudgmentCourt_VenueName.isReadOnly = function(){ return false; }
		    JudgmentCourt_VenueName.isTemporary = function(){ return true; }
		    JudgmentCourt_VenueName.maxLength = 30;
		    JudgmentCourt_VenueName.helpText = "Name of the Court.";
		    JudgmentCourt_VenueName.isMandatory = function(){ return true; }
		    JudgmentCourt_VenueName.validate = function(){ return null; }
		    JudgmentCourt_VenueName.srcData = REF_DATA_XPATH + "/Courts";
		    JudgmentCourt_VenueName.rowXPath = "Court";
		    JudgmentCourt_VenueName.keyXPath = "Code";
		    JudgmentCourt_VenueName.displayXPath = "Name";
		    JudgmentCourt_VenueName.logicOn  = [JudgmentCourt_VenueName.dataBinding];
		    JudgmentCourt_VenueName.logic = function()
		    {
		        var codeOrName = Services.getValue(JudgmentCourt_VenueName.dataBinding);      
		        var xpathId = REF_DATA_XPATH + "/Courts/Court[Code = " + JudgmentCourt_VenueName.dataBinding + "]/Code";
		        var code = Services.getValue(xpathId);
		        if(code == null || "" == code)
		        {
		        	var name = Services.getValue(JudgmentCourt_VenueName.dataBinding);     
					code = Services.getValue(REF_DATA_XPATH + "/Courts/Court[Name = " + JudgmentCourt_VenueName.dataBinding + "]/Code");	
		        }
				if( code != null && code != "")
				{ 	
					Services.setValue(JudgmentCourt_VenueCode.dataBinding, code);  		
				}
				else
				{
					Services.setValue(JudgmentCourt_VenueName.dataBinding, "");
					Services.setValue(JudgmentCourt_VenueCode.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_Line1.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_Line2.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_Line3.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_Line4.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_Line5.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_Postcode.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_DXNumber.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_TelephoneNumber.dataBinding, "");
					Services.setValue(JudgmentCourt_ContactDetails_Address_FaxNumber.dataBinding, "");
					Services.setValue(JudgmentCourtCourtsLOVGrid.dataBinding, ""); 
				}

		    }
		    /**
		    JudgmentCourt_VenueName.validateOn = [JudgmentCourt_VenueName.dataBinding];
		    JudgmentCourt_VenueName.validate = function()
		    {
		        var venueCode = Services.getValue(JudgmentCourt_VenueCode.dataBinding);
		        var venueDesc = Services.getValue(JudgmentCourt_VenueName.dataBinding); 
		        var errCode = null;
		        if(venueCode != null && venueCode != ""){               
		            // need to ensure that correct value has been entered.  
		            // If a one has there will be a corresponding Description
		            // &&& NB Will need to look at this in future when auto complete is implemented
		            if(venueDesc == null || venueDesc ==""){
		                errCode = ErrorCode.getErrorCode('CaseMan_invalidCourtCode_Msg');
		            }   
		        }// end of if(typeCode != null && typeCode != ""){  
		        return errCode;     
		    }
