		//------------------------------------  JudgmentCourtCourtsLOVGrid  ----------------------------------------------
		
		
			function JudgmentCourtCourtsLOVGrid() {};
			JudgmentCourtCourtsLOVGrid.dataBinding = "/ds/var/page/SelectedLOVRow/OwningCourt";
			JudgmentCourtCourtsLOVGrid.srcData = REF_DATA_XPATH + "/Courts";
			JudgmentCourtCourtsLOVGrid.rowXPath = "Court";
			JudgmentCourtCourtsLOVGrid.keyXPath = "Code";
			JudgmentCourtCourtsLOVGrid.columns = [
			    {xpath: "Code"},
			    {xpath: "Name"}
			];
			
			// Configure the location in the model which will generate data change events
			JudgmentCourtCourtsLOVGrid.logicOn = [JudgmentCourtCourtsLOVGrid.dataBinding];
			// Implement the callback
			JudgmentCourtCourtsLOVGrid.logic = function()
			{
			    var id = Services.getValue(JudgmentCourtCourtsLOVGrid.dataBinding);
			   
			    if (id != null && "" != id)
			    {
			        // Lookup the hearing type in ref data from the code that is stored in value
			        var xpathCode = REF_DATA_XPATH + "/Courts/Court[Code = " + id + "]/Code";     
			        var xpathName = REF_DATA_XPATH + "/Courts/Court[Code = " + id + "]/Name";     
			        var courtCode = Services.getValue(xpathCode);
			        var courtName = Services.getValue(xpathName);
			        
			        // Set the data in the business part of the model
			        Services.setValue(JudgmentCourt_VenueCode.dataBinding, id);
			        Services.setValue(JudgmentCourt_VenueName.dataBinding, id);         
			        //write here
		  		}
		  		else
		  		{
			        Services.setValue(JudgmentCourt_VenueCode.dataBinding, "");
			        Services.setValue(JudgmentCourt_VenueName.dataBinding, ""); 
		  		}
			} // end of logic()
		
		
		//--------------------------------  JudgmentCourt_Address_Grid --------------------------------------------
		
		function JudgmentCourt_Address_Grid(){};
		JudgmentCourt_Address_Grid.dataBinding = "/ds/var/page/SelectedGridRow/SelectedAddress"; 
		JudgmentCourt_Address_Grid.srcData = REF_DATA_XPATH + "/Courts/Court[./Code = " + JudgmentCourtCourtsLOVGrid.dataBinding + "]/ContactDetails"; 
		JudgmentCourt_Address_Grid.rowXPath = "Address";        // Individual Court/venue
		JudgmentCourt_Address_Grid.keyXPath = "AddressId";      // Unique identifier for a Court/venue
		JudgmentCourt_Address_Grid.columns = [                  // column bindings
		    {xpath: "Line[1]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}},
		    {xpath: "Line[2]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}}
		];
		
		JudgmentCourt_Address_Grid.retrieveOn = [JudgmentCourtCourtsLOVGrid.dataBinding];
		JudgmentCourt_Address_Grid.srcDataOn = [JudgmentCourtCourtsLOVGrid.dataBinding];
		
		// When  a different Address row is selected
		JudgmentCourt_Address_Grid.logicOn = [JudgmentCourt_Address_Grid.dataBinding,
		                                    JudgmentCourtCourtsLOVGrid.dataBinding];
		
		// Get the associated Address Data
		JudgmentCourt_Address_Grid.logic = function()
		{
		    var courtId = Services.getValue(JudgmentCourtCourtsLOVGrid.dataBinding);
		    var addressId = Services.getValue(JudgmentCourt_Address_Grid.dataBinding);
		    if (courtId != null && addressId != null && "" != courtId  && "" != addressId){
		        // Set the address details as necessary.
		        // Set up xpaths
		        var b11 = REF_DATA_XPATH + "/Courts/Court[./Code = ";
		        var b13 = "]/ContactDetails/";
		        var b12 = b13 + "Address[./AddressId = ";
		        var xpathAdd1 = b11 + courtId + b12 + addressId + "]/Line[1]";  
		        var xpathAdd2 = b11  + courtId + b12 + addressId + "]/Line[2]"; 
		        var xpathAdd3 = b11  + courtId + b12 + addressId + "]/Line[3]"; 
		        var xpathAdd4 = b11  + courtId + b12 + addressId + "]/Line[4]"; 
		        var xpathAdd5 = b11  + courtId + b12 + addressId + "]/Line[5]"; 
		        var xpathPostcode = b11  + courtId + b12 + addressId + "]/PostCode";    
		        var xpathDXNo  = b11 + courtId + b13 +"DX"; 
		        var xpathTelNo = b11 + courtId + b13 +"TelephoneNumber";    
		        var xpathFaxNo = b11 + courtId + b13 +"FaxNumber";  
		        
		        // retrieve values from the DOM
		        var add1 = Services.getValue(xpathAdd1);
		        var add2 = Services.getValue(xpathAdd2);
		        // ensure not adding a null - as these fields are not mandatory     
		        var add3 = Services.getValue(xpathAdd3);
		        if(add3 == null){add3 = ""; }   
		        var add4 = Services.getValue(xpathAdd4);
		        if(add3 == null){add4 = "";}
		        var add5 = Services.getValue(xpathAdd5);
		        if(add3 == null){add5 = ""; }
		        var postcode = Services.getValue(xpathPostcode);        
		        var dxNo = Services.getValue(xpathDXNo);
		        if(dxNo == null){dxNo = ""; }
		        var telNo = Services.getValue(xpathTelNo);
		        if(telNo == null){  telNo = ""; }
		        var faxNo = Services.getValue(xpathFaxNo);
		        if(telNo == null){telNo= "";}
		        
		        // Set the data in the tmp part of the model
		        Services.setValue(JudgmentCourt_ContactDetails_Address_Line1.dataBinding, add1);
		        Services.setValue(JudgmentCourt_ContactDetails_Address_Line2.dataBinding, add2);
		        Services.setValue(JudgmentCourt_ContactDetails_Address_Line3.dataBinding, add3);
		        Services.setValue(JudgmentCourt_ContactDetails_Address_Line4.dataBinding, add4);
		        Services.setValue(JudgmentCourt_ContactDetails_Address_Line5.dataBinding, add5);
		        Services.setValue(JudgmentCourt_ContactDetails_Address_Postcode.dataBinding, postcode);     
		        Services.setValue(JudgmentCourt_ContactDetails_Address_DXNumber.dataBinding, dxNo);
		        Services.setValue(JudgmentCourt_ContactDetails_Address_TelephoneNumber.dataBinding, telNo);
		        Services.setValue(JudgmentCourt_ContactDetails_Address_FaxNumber.dataBinding, faxNo);       
		    }
		} 
		
		// end of logic()
				
		
		//---------------------------------- JudgmentCourt_VenueLOVBtn ------------------------------
		
		
		function JudgmentCourt_VenueLOVBtn() {}
		JudgmentCourt_VenueLOVBtn.tabIndex = __tabIdx++;
		
		/** PostBuildX 15a **/
		JudgmentCourtCourtsLOVGrid.raise = {
			eventBinding: {
				singleClicks: [ {element: "JudgmentCourt_VenueLOVBtn"} ],
				keys: [ { key: Key.F6, element: "JudgmentCourt_VenueCode" }, { key: Key.F6, element: "JudgmentCourt_VenueName" } ]
			}
		};
